 1→import axios from 'axios'
 2→import type { Task, PageResponse, CreateTaskRequest } from '@/types/task'
 3→
 4→const apiClient = axios.create({
 5→  baseURL: '',
 6→})
 7→
 8→apiClient.interceptors.request.use((config) => {
 9→  const token = localStorage.getItem('token')
10→  if (token) {
11→    config.headers['Authorization'] = `Bearer ${token}`
12→  }
13→  return config
14→})
15→
16→interface FetchTasksParams {
17→  page?: number
18→  size?: number
19→  keyword?: string | null
20→  priority?: string | null
21→  status?: string | null
22→}
23→
24→export async function fetchTasks(params: FetchTasksParams = {}): Promise<PageResponse<Task>> {
25→  const queryParams: Record<string, any> = {
26→    page: params.page ?? 0,
27→    size: params.size ?? 20,
28→  }
29→  if (params.keyword) {
30→    queryParams.keyword = params.keyword
31→  }
32→  if (params.priority) {
33→    queryParams.priority = params.priority
34→  }
35→  if (params.status) {
36→    queryParams.status = params.status
37→  }
38→  const response = await apiClient.get('/api/tasks', { params: queryParams })
39→  return response.data
40→}
41→
42→export async function createTask(data: CreateTaskRequest | Record<string, any>): Promise<Task> {
43→  const response = await apiClient.post('/api/tasks', data)
44→  return response.data
45→}
46→
47→export async function getTask(id: number): Promise<Task> {
48→  const response = await apiClient.get(`/api/tasks/${id}`)
49→  return response.data
50→}
